INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '665867ba-8f40-4319-be33-9b2cfa824ca8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Python Profiling — Finding Real Bottlenecks with cProfile and line_profiler$escape$,
  $escape$Python's GIL and dynamic dispatch make performance intuition unreliable — you must measure. `cProfile` is the standard entry point: it instruments every function call with near-zero overhead and reports cumulative time, call count, and per-call averages. Run it as `python -m cProfile -s cumulative script.py` or wrap a specific function with `cProfile.Profile().runcall()`. The output's `tottime` (time in function, excluding callees) vs `cumtime` (inclusive) distinction is critical — a high `cumtime` with low `tottime` means the real cost is downstream.

For line-level granularity, `line_profiler` (via `kernprof`) decorates functions with `@profile` and shows time per statement — essential for NumPy-heavy code where a single vectorized call hides O(n²) behavior. Pair this with `memory_profiler` for heap analysis. Avoid `time.time()` micro-benchmarks for anything except wall-clock I/O checks; use `timeit.timeit()` for isolated expression benchmarking, which handles GC suppression and loop repetition automatically. Always profile under realistic data volumes — Python's overhead characteristics shift dramatically between 100 and 100,000 items.$escape$,
  $escape$import cProfile
import pstats
import io
from line_profiler import LineProfiler

def slow_function(data: list[int]) -> list[int]:
    return [x ** 2 for x in data if x % 2 == 0]

# cProfile: function-level
pr = cProfile.Profile()
pr.enable()
result = slow_function(list(range(100_000)))
pr.disable()

stream = io.StringIO()
ps = pstats.Stats(pr, stream=stream).sort_stats('cumulative')
ps.print_stats(10)
print(stream.getvalue())

# line_profiler: line-level (run via: kernprof -l -v script.py)
# @profile  # uncomment when running with kernprof
# def slow_function(data): ...$escape$,
  $escape$python$escape$,
