INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b12d924a-9c6e-438f-90c5-100073d84786',
  '00000000-0000-0000-0000-000000000001',
  $escape$Python Deployment — Shrinking Images, Binaries, and Runtime Baggage$escape$,
  $escape$Unlike Go or Rust, Python ships no single self-contained binary. Every deployment drags along the interpreter, stdlib, and every transitive dependency. Docker multi-stage builds are the first lever: compile wheels in a full `python:3.12` stage, then copy only `site-packages` and your app into a `python:3.12-slim` final stage — shaving hundreds of MBs. Use `pip install --no-cache-dir --no-deps -r requirements.txt` in the build stage and pin with `pip-compile` (pip-tools) to lock exact hashes. For true single-binary deploys, `PyInstaller` bundles the interpreter and all imports into one executable via `--onefile`, but watch for hidden imports with `--collect-submodules`. `Nuitka` goes further — it transpiles Python to C and compiles it, producing a native binary with no interpreter overhead. For Lambda or serverless, strip dev deps with `pip install --only-binary=:all:` and use Lambda layers to share the runtime across functions. Always audit with `pip-audit` before shipping to catch CVEs in pinned deps.$escape$,
  $escape$# Multi-stage Dockerfile for a slim Python image
FROM python:3.12 AS builder
WORKDIR /app
COPY requirements.txt .
RUN pip install --no-cache-dir --no-deps -r requirements.txt --target /app/deps

FROM python:3.12-slim AS runtime
WORKDIR /app
COPY --from=builder /app/deps /app/deps
COPY src/ ./src/
ENV PYTHONPATH=/app/deps
CMD ["python", "src/main.py"]$escape$,
  $escape$bash$escape$,
