INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7e04ca95-eddb-4a39-9784-b38c890cb2d4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Python's GIL — Why Horizontal Scaling Beats Vertical Threading$escape$,
  $escape$CPython's Global Interpreter Lock (GIL) ensures only one thread executes Python bytecode at a time, regardless of CPU count. For CPU-bound workloads, `threading.Thread` gives you concurrency theater — all threads contend for the same lock, serial execution. The real tool is `multiprocessing.Process` or `concurrent.futures.ProcessPoolExecutor`, which forks separate interpreter instances each with their own GIL, achieving true parallelism.

This constraint defines Python's horizontal scaling story. Production web apps scale via process multiplication — Gunicorn's `--workers $(nproc)` or Uvicorn's `--workers` flag — not threads per process. Each worker is an independent CPython interpreter. Memory scales linearly; Linux's copy-on-write fork semantics delay the cost until pages are dirtied.

For I/O-bound work, `asyncio` sidesteps the GIL entirely. A single-threaded event loop multiplexes thousands of connections via `select`/`epoll`. FastAPI, Starlette, and async SQLAlchemy are architected around this model — one process, zero threads, high throughput.

CPython 3.13 ships GIL removal as opt-in (`PYTHON_GIL=0`). Many C extensions (NumPy, pandas) still internally acquire and release it — benchmark before relying on free-threaded mode in production.$escape$,
  $escape$from concurrent.futures import ProcessPoolExecutor, ThreadPoolExecutor
import time

def cpu_bound(n: int) -> int:
    return sum(i * i for i in range(n))

# GIL serializes threads — no speedup on CPU-bound work
with ThreadPoolExecutor(max_workers=4) as ex:
    t0 = time.perf_counter()
    list(ex.map(cpu_bound, [10_000_000] * 4))
    print(f"threads:   {time.perf_counter() - t0:.2f}s")  # ~4x baseline

# Each process has its own GIL — true parallelism
with ProcessPoolExecutor(max_workers=4) as ex:
    t0 = time.perf_counter()
    list(ex.map(cpu_bound, [10_000_000] * 4))
    print(f"processes: {time.perf_counter() - t0:.2f}s")  # ~1x baseline$escape$,
  $escape$python$escape$,
